mapper.update:
UPDATE project
SET is_lock = 'L1'
WHERE id = #{id}
  AND NOT EXISTS (
  /* 하위 프로젝트 중 잠금되지 않은(L0) 프로젝트가 있는지 확인 */
  SELECT 1
  FROM project
  WHERE is_lock = 'L0'
    AND id != #{id}  -- 자기 자신은 제외
  START WITH parent_id = #{id}
  CONNECT BY PRIOR id = parent_id
)

UPDATE project
SET is_lock = 'L0'
WHERE id = #{id}

UPDATE project p
SET p.status = 'K0'
WHERE p.id = #{id}
AND NOT EXISTS(
    SELECT 1
    FROM project child
    WHERE child.parent_id = #{id}
    AND child.status != 'K0'
)

